11	template <typename... T>
12	ErrCode logError(const ErrCode &Code, const AST::Instruction &Instr,
13	                 T &&...F) noexcept {
14	  spdlog::error(Code);
15	  (F(), ...);
16	  spdlog::error(ErrInfo::InfoInstruction(Instr.getOpCode(), Instr.getOffset()));
17	  return Code;
18	}
