20	ErrCode logError(const ErrCode &Code, const AST::Instruction &Instr) noexcept {
21	  spdlog::error(Code);
22	  spdlog::error(ErrInfo::InfoInstruction(Instr.getOpCode(), Instr.getOffset()));
23	  return Code;
