363	Expect<void> Executor::runRefConvOp(RefVariant &Ref,
364	                                    TypeCode TCode) const noexcept {
365	  if (TCode == TypeCode::AnyRef) {
366	    // Internalize.
367	    if (Ref.isNull()) {
368	      Ref = RefVariant(ValType(TypeCode::RefNull, TypeCode::NullRef));
369	    } else {
370	      Ref.getType().setInternalized();
371	      if (Ref.getType().isExternRefType()) {
372	        Ref.getType() = ValType(TypeCode::Ref, TypeCode::AnyRef);
373	      }
374	    }
375	  } else {
376	    // Externalize.
377	    if (Ref.isNull()) {
378	      Ref = RefVariant(ValType(TypeCode::RefNull, TypeCode::NullExternRef));
379	    } else {
380	      // Use the externalize flag because the value type information should be
381	      // reserved when a reference being externalized and internalized.
382	      Ref.getType().setExternalized();
383	    }
384	  }
385	  return {};
386	}
