395	Expect<void> Executor::runI31GetOp(ValVariant &Val,
396	                                   const AST::Instruction &Instr,
397	                                   const bool IsSigned) const noexcept {
398	  uint32_t RefNum = static_cast<uint32_t>(
399	      reinterpret_cast<uintptr_t>(Val.get<RefVariant>().getPtr<void>()));
400	  if ((RefNum & 0x80000000U) == 0) {
401	    return Unexpect(logError(ErrCode::Value::AccessNullI31, Instr));
402	  }
403	  RefNum &= 0x7FFFFFFFU;
404	  if (IsSigned) {
405	    RefNum |= ((RefNum & 0x40000000U) << 1);
406	  }
407	  Val.emplace<uint32_t>(RefNum);
408	  return {};
409	}
