411	Expect<RefVariant>
412	Executor::structNew(Runtime::StackManager &StackMgr, const uint32_t TypeIdx,
413	                    Span<const ValVariant> Args) const noexcept {
414	  /// TODO: The array and struct instances are owned by the module instance
415	  /// currently because of referring the defined types of the module instances.
416	  /// This may be changed after applying the garbage collection mechanism.
417	  const auto &CompType = getCompositeTypeByIdx(StackMgr, TypeIdx);
418	  uint32_t N = static_cast<uint32_t>(CompType.getFieldTypes().size());
419	  Runtime::Instance::ModuleInstance *ModInst =
420	      const_cast<Runtime::Instance::ModuleInstance *>(StackMgr.getModule());
421	  std::vector<ValVariant> Vals(N);
422	  for (uint32_t I = 0; I < N; I++) {
423	    const auto &VType = CompType.getFieldTypes()[I].getStorageType();
424	    if (Args.size() > 0) {
425	      Vals[I] = packVal(VType, Args[I]);
426	    } else {
427	      Vals[I] = VType.isRefType()
428	                    ? ValVariant(RefVariant(toBottomType(StackMgr, VType)))
429	                    : ValVariant(static_cast<uint128_t>(0U));
430	    }
431	  }
432	  WasmEdge::Runtime::Instance::StructInstance *Inst =
433	      ModInst->newStruct(TypeIdx, std::move(Vals));
434	  return RefVariant(Inst->getDefType(), Inst);
435	}
