463	Expect<RefVariant>
464	Executor::arrayNew(Runtime::StackManager &StackMgr, const uint32_t TypeIdx,
465	                   const uint32_t Length,
466	                   Span<const ValVariant> Args) const noexcept {
467	  /// TODO: The array and struct instances are owned by the module instance
468	  /// currently because of referring the defined types of the module instances.
469	  /// This may be changed after applying the garbage collection mechanism.
470	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
471	  WasmEdge::Runtime::Instance::ArrayInstance *Inst = nullptr;
472	  Runtime::Instance::ModuleInstance *ModInst =
473	      const_cast<Runtime::Instance::ModuleInstance *>(StackMgr.getModule());
474	  if (Args.size() == 0) {
475	    // New and fill with default values.
476	    auto InitVal = VType.isRefType()
477	                       ? ValVariant(RefVariant(toBottomType(StackMgr, VType)))
478	                       : ValVariant(static_cast<uint128_t>(0U));
479	    Inst = ModInst->newArray(TypeIdx, Length, InitVal);
480	  } else if (Args.size() == 1) {
481	    // New and fill with the arg value.
482	    Inst = ModInst->newArray(TypeIdx, Length, packVal(VType, Args[0]));
483	  } else {
484	    // New with args.
485	    Inst = ModInst->newArray(
486	        TypeIdx,
487	        packVals(VType, std::vector<ValVariant>(Args.begin(), Args.end())));
488	  }
