492	Expect<RefVariant>
493	Executor::arrayNewData(Runtime::StackManager &StackMgr, const uint32_t TypeIdx,
494	                       const uint32_t DataIdx, const uint32_t Start,
495	                       const uint32_t Length) const noexcept {
496	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
497	  const uint32_t BSize = VType.getBitWidth() / 8;
498	  auto *DataInst = getDataInstByIdx(StackMgr, DataIdx);
499	  assuming(DataInst);
500	  if (static_cast<uint64_t>(Start) + static_cast<uint64_t>(Length) * BSize >
501	      DataInst->getData().size()) {
502	    return Unexpect(ErrCode::Value::MemoryOutOfBounds);
503	  }
504	  Runtime::Instance::ModuleInstance *ModInst =
505	      const_cast<Runtime::Instance::ModuleInstance *>(StackMgr.getModule());
506	  std::vector<ValVariant> Args;
507	  Args.reserve(Length);
508	  for (uint32_t Idx = 0; Idx < Length; Idx++) {
509	    // The value has been packed.
510	    Args.push_back(DataInst->loadValue(Start + Idx * BSize, BSize));
511	  }
512	  WasmEdge::Runtime::Instance::ArrayInstance *Inst =
513	      ModInst->newArray(TypeIdx, std::move(Args));
514	  return RefVariant(Inst->getDefType(), Inst);
515	}
