517	Expect<RefVariant>
518	Executor::arrayNewElem(Runtime::StackManager &StackMgr, const uint32_t TypeIdx,
519	                       const uint32_t ElemIdx, const uint32_t Start,
520	                       const uint32_t Length) const noexcept {
521	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
522	  auto *ElemInst = getElemInstByIdx(StackMgr, ElemIdx);
523	  assuming(ElemInst);
524	  auto ElemSrc = ElemInst->getRefs();
525	  if (static_cast<uint64_t>(Start) + static_cast<uint64_t>(Length) >
526	      ElemSrc.size()) {
527	    return Unexpect(ErrCode::Value::TableOutOfBounds);
528	  }
529	  std::vector<ValVariant> Refs(ElemSrc.begin() + Start,
530	                               ElemSrc.begin() + Start + Length);
531	  Runtime::Instance::ModuleInstance *ModInst =
532	      const_cast<Runtime::Instance::ModuleInstance *>(StackMgr.getModule());
533	  WasmEdge::Runtime::Instance::ArrayInstance *Inst =
534	      ModInst->newArray(TypeIdx, packVals(VType, std::move(Refs)));
535	  return RefVariant(Inst->getDefType(), Inst);
536	}
537	
538	Expect<ValVariant> Executor::arrayGet(Runtime::StackManager &StackMgr,
539	                                      const RefVariant &Ref,
540	                                      const uint32_t TypeIdx,
541	                                      const uint32_t Idx,
542	                                      const bool IsSigned) const noexcept {
543	  const auto *Inst = Ref.getPtr<Runtime::Instance::ArrayInstance>();
544	  if (Inst == nullptr) {
545	    return Unexpect(ErrCode::Value::AccessNullArray);
546	  }
547	  if (Idx >= Inst->getLength()) {
548	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
549	  }
550	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
551	  return unpackVal(VType, Inst->getData(Idx), IsSigned);
552	}
553	
554	Expect<void> Executor::arraySet(Runtime::StackManager &StackMgr,
555	                                const RefVariant &Ref, const ValVariant &Val,
556	                                const uint32_t TypeIdx,
557	                                const uint32_t Idx) const noexcept {
558	  auto *Inst = Ref.getPtr<Runtime::Instance::ArrayInstance>();
559	  if (Inst == nullptr) {
560	    return Unexpect(ErrCode::Value::AccessNullArray);
561	  }
562	  if (Idx >= Inst->getLength()) {
563	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
564	  }
565	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
566	  Inst->getData(Idx) = packVal(VType, Val);
