570	Expect<void> Executor::arrayFill(Runtime::StackManager &StackMgr,
571	                                 const RefVariant &Ref, const ValVariant &Val,
572	                                 const uint32_t TypeIdx, const uint32_t Idx,
573	                                 const uint32_t Cnt) const noexcept {
574	  auto *Inst = Ref.getPtr<Runtime::Instance::ArrayInstance>();
575	  if (Inst == nullptr) {
576	    return Unexpect(ErrCode::Value::AccessNullArray);
577	  }
578	  if (static_cast<uint64_t>(Idx) + static_cast<uint64_t>(Cnt) >
579	      Inst->getLength()) {
580	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
581	  }
582	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
583	  auto Arr = Inst->getArray();
584	  std::fill(Arr.begin() + Idx, Arr.begin() + Idx + Cnt, packVal(VType, Val));
585	  return {};
