587	
588	Expect<void>
589	Executor::arrayInitData(Runtime::StackManager &StackMgr, const RefVariant &Ref,
590	                        const uint32_t TypeIdx, const uint32_t DataIdx,
591	                        const uint32_t DstIdx, const uint32_t SrcIdx,
592	                        const uint32_t Cnt) const noexcept {
593	  auto *Inst = Ref.getPtr<Runtime::Instance::ArrayInstance>();
594	  if (Inst == nullptr) {
595	    return Unexpect(ErrCode::Value::AccessNullArray);
596	  }
597	  if (static_cast<uint64_t>(DstIdx) + static_cast<uint64_t>(Cnt) >
598	      Inst->getLength()) {
599	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
600	  }
601	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
602	  const uint32_t BSize = VType.getBitWidth() / 8;
603	  auto *DataInst = getDataInstByIdx(StackMgr, DataIdx);
604	  assuming(DataInst);
605	  if (static_cast<uint64_t>(SrcIdx) + static_cast<uint64_t>(Cnt) * BSize >
606	      DataInst->getData().size()) {
607	    return Unexpect(ErrCode::Value::MemoryOutOfBounds);
608	  }
609	
610	  for (uint32_t Idx = 0; Idx < Cnt; Idx++) {
611	    // The value has been packed.
612	    Inst->getData(DstIdx + Idx) =
613	        DataInst->loadValue(SrcIdx + Idx * BSize, BSize);
614	  }
615	  return {};
616	}
617	
618	Expect<void>
619	Executor::arrayInitElem(Runtime::StackManager &StackMgr, const RefVariant &Ref,
620	                        const uint32_t TypeIdx, const uint32_t ElemIdx,
621	                        const uint32_t DstIdx, const uint32_t SrcIdx,
622	                        const uint32_t Cnt) const noexcept {
623	  auto *Inst = Ref.getPtr<Runtime::Instance::ArrayInstance>();
624	  if (Inst == nullptr) {
625	    return Unexpect(ErrCode::Value::AccessNullArray);
626	  }
627	  if (static_cast<uint64_t>(DstIdx) + static_cast<uint64_t>(Cnt) >
628	      Inst->getLength()) {
629	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
630	  }
631	  const auto &VType = getArrayStorageTypeByIdx(StackMgr, TypeIdx);
632	  auto *ElemInst = getElemInstByIdx(StackMgr, ElemIdx);
633	  assuming(ElemInst);
634	  auto ElemSrc = ElemInst->getRefs();
635	  if (static_cast<uint64_t>(SrcIdx) + static_cast<uint64_t>(Cnt) >
636	      ElemSrc.size()) {
637	    return Unexpect(ErrCode::Value::TableOutOfBounds);
638	  }
639	
640	  auto Arr = Inst->getArray();
641	  // The value has been packed.
642	  std::transform(ElemSrc.begin() + SrcIdx, ElemSrc.begin() + SrcIdx + Cnt,
643	                 Arr.begin() + DstIdx,
644	                 [&](const RefVariant &V) { return packVal(VType, V); });
645	  return {};
646	}
647	
648	Expect<void>
649	Executor::arrayCopy(Runtime::StackManager &StackMgr, const RefVariant &DstRef,
650	                    const uint32_t DstTypeIdx, const uint32_t DstIdx,
651	                    const RefVariant &SrcRef, const uint32_t SrcTypeIdx,
652	                    const uint32_t SrcIdx, const uint32_t Cnt) const noexcept {
653	  auto *SrcInst = SrcRef.getPtr<Runtime::Instance::ArrayInstance>();
654	  auto *DstInst = DstRef.getPtr<Runtime::Instance::ArrayInstance>();
655	  if (SrcInst == nullptr) {
656	    return Unexpect(ErrCode::Value::AccessNullArray);
657	  }
658	  if (DstInst == nullptr) {
659	    return Unexpect(ErrCode::Value::AccessNullArray);
660	  }
661	  if (static_cast<uint64_t>(SrcIdx) + static_cast<uint64_t>(Cnt) >
662	      SrcInst->getLength()) {
663	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
664	  }
665	  if (static_cast<uint64_t>(DstIdx) + static_cast<uint64_t>(Cnt) >
666	      DstInst->getLength()) {
667	    return Unexpect(ErrCode::Value::ArrayOutOfBounds);
668	  }
669	
670	  auto SrcArr = SrcInst->getArray();
671	  auto DstArr = DstInst->getArray();
672	  const auto &SrcVType = getArrayStorageTypeByIdx(StackMgr, SrcTypeIdx);
673	  const auto &DstVType = getArrayStorageTypeByIdx(StackMgr, DstTypeIdx);
674	  if (DstIdx <= SrcIdx) {
675	    std::transform(SrcArr.begin() + SrcIdx, SrcArr.begin() + SrcIdx + Cnt,
676	                   DstArr.begin() + DstIdx, [&](const ValVariant &V) {
677	                     return packVal(DstVType, unpackVal(SrcVType, V));
678	                   });
679	  } else {
680	    std::transform(std::make_reverse_iterator(SrcArr.begin() + SrcIdx + Cnt),
681	                   std::make_reverse_iterator(SrcArr.begin() + SrcIdx),
682	                   std::make_reverse_iterator(DstArr.begin() + DstIdx + Cnt),
683	                   [&](const ValVariant &V) {
684	                     return packVal(DstVType, unpackVal(SrcVType, V));
685	                   });
686	  }
687	  return {};
688	}
