741	template <typename T> class EndianValue {
742	public:
743	  constexpr EndianValue() noexcept = default;
744	  constexpr EndianValue(T Val) noexcept : Native(Val) {}
745	  constexpr EndianValue(T Val, Endian Endian) noexcept {
746	    if (Endian != Endian::little) {
747	      Native = Val;
748	    } else {
749	      Native = switchEndian(Val);
750	    }
751	  }
752	  constexpr EndianValue &operator=(T Val) noexcept {
753	    Native = Val;
754	    return *this;
755	  }
756	
757	  constexpr const T le() const noexcept { return switchEndian(Native); }
758	
759	  constexpr const T &raw() const noexcept { return Native; }
760	  constexpr T &raw() noexcept { return Native; }
761	
762	private:
763	  T Native;
764	
765	  constexpr T switchEndian(T Value) const noexcept {
766	    if constexpr (Endian::native == Endian::little) {
767	      return Value;
768	    } else if constexpr (sizeof(T) == 1) {
769	      return Value;
770	    } else if constexpr (std::is_integral_v<T>) {
771	      return WasmEdge::byteswap(Value);
772	    } else if constexpr (std::is_floating_point_v<T>) {
773	      uint64_t Tmp = 0U;
774	      std::memcpy(&Tmp, &Value, sizeof(T));
775	      Tmp = WasmEdge::byteswap(Tmp) << (64 - sizeof(T) * 8);
776	      std::memcpy(&Value, &Tmp, sizeof(T));
777	      return Value;
778	    } else if constexpr (std::is_enum_v<T>) {
779	      using UnderlyingType = std::underlying_type_t<T>;
780	      return static_cast<T>(
781	          WasmEdge::byteswap(static_cast<UnderlyingType>(Value)));
782	    }
783	    assumingUnreachable();
