    return static_cast<uint64_t>(Val.get<uint64_t>());
  default:
    assumingUnreachable();
  }
}

inline ValVariant emplaceAddr(const uint64_t Addr,
                              const AddressType AT) noexcept {
  switch (AT) {
  case AddressType::I32:
    return static_cast<uint32_t>(Addr);
  case AddressType::I64:
    return static_cast<uint64_t>(Addr);
  default:
    assumingUnreachable();
  }
}

inline uint64_t getMaxAddress(const AddressType AT) noexcept {
  switch (AT) {
  case AddressType::I32:
    return static_cast<uint64_t>(std::numeric_limits<uint32_t>::max());
  case AddressType::I64:
    return static_cast<uint64_t>(std::numeric_limits<uint64_t>::max());
  default:
    assumingUnreachable();
  }
}

// <<<<<<<< Functions to access address value from ValVariant <<<<<<<<<<<<<<<<<<

/// EndianValue definition.
template <typename T> class EndianValue {
public:
  constexpr EndianValue() noexcept = default;
  constexpr EndianValue(T Val) noexcept : Native(Val) {}
  constexpr EndianValue(T Val, Endian Endian) noexcept {
    if (Endian != Endian::little) {
      Native = Val;
    } else {
      Native = switchEndian(Val);
    }
  }
  constexpr EndianValue &operator=(T Val) noexcept {
    Native = Val;
    return *this;
  }

  constexpr const T le() const noexcept { return switchEndian(Native); }

  constexpr const T &raw() const noexcept { return Native; }
  constexpr T &raw() noexcept { return Native; }

private:
  T Native;

  constexpr T switchEndian(T Value) const noexcept {
    if constexpr (Endian::native == Endian::little) {
      return Value;
    } else if constexpr (sizeof(T) == 1) {
      return Value;
    } else if constexpr (std::is_integral_v<T>) {
      return WasmEdge::byteswap(Value);
    } else if constexpr (std::is_floating_point_v<T>) {
      uint64_t Tmp = 0U;
      std::memcpy(&Tmp, &Value, sizeof(T));
      Tmp = WasmEdge::byteswap(Tmp) << (64 - sizeof(T) * 8);
      std::memcpy(&Value, &Tmp, sizeof(T));
      return Value;
    } else if constexpr (std::is_enum_v<T>) {
      using UnderlyingType = std::underlying_type_t<T>;
      return static_cast<T>(
          WasmEdge::byteswap(static_cast<UnderlyingType>(Value)));
    }
    assumingUnreachable();
  }
};

} // namespace WasmEdge

template <>
struct fmt::formatter<WasmEdge::ValType> : fmt::formatter<std::string_view> {
  fmt::format_context::iterator
  format(const WasmEdge::ValType &Type,
         fmt::format_context &Ctx) const noexcept {
    using namespace std::literals;
    // For the number types, print the type directly.
    if (!Type.isRefType()) {
      return formatter<std::string_view>::format(
          WasmEdge::TypeCodeStr[Type.getCode()], Ctx);
    }
    // For the reference types, print the details.
    fmt::memory_buffer Buffer;
    fmt::format_to(std::back_inserter(Buffer), "{} {}"sv,
                   WasmEdge::TypeCodeStr[Type.getCode()],
                   WasmEdge::TypeCodeStr[Type.getHeapTypeCode()]);
    if (Type.getHeapTypeCode() == WasmEdge::TypeCode::TypeIndex) {
      fmt::format_to(std::back_inserter(Buffer), "[{}]"sv, Type.getTypeIndex());
    }
    return formatter<std::string_view>::format(
        std::string_view(Buffer.data(), Buffer.size()), Ctx);
  }
};

